  ('real-estate-moex-00864', 'real-estate', 'real-estate-moex-106-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依消費者保護法規定，關於企業經營者責任之敘述，下列何者錯誤？ 企業經營者所提供之服務，若具有危害消費者健康之可能者，應為警告標示。違反且致生損害於消費 者時應負連帶賠償責任 從事經銷之企業經營者，對商品或服務所生之損害防免已盡相當之注意，無須負連帶賠償責任 企業經營者之商品雖致生損害於消費者，若能證明其無過失者，則無須負連帶損害賠償責任 企業經營者對於商品符合可合理期待之安全性，負舉證責任', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "0ce5bf5d4f9f", "answer_pdf_sha1": "2b4255695cb0", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 24, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
